%[text] ## Section 6: Emax 薬力学モデルと有効性ウィンドウ
%[text] ### 血漿濃度と臨床効果の関連付け
%[text] Emax（Hill）モデルは血漿濃度 $C$ と薬理効果 $E$ の関係を定義します。
%[text] 一般形 $E(C) = \\frac{E(max) \\cdot C^n}{EC50^n + C^n}$ において、$n = 1$ の場合（協同結合なし; 標準的な鎮痛薬・覚醒薬）は $E(C) = \\frac{E(max) \\cdot C}{EC50 + C}$ となります。
%[text] 
%[text] 治療ウィンドウの目安を以下に示します。
%[text] $C \\geq EC50$ のとき薬物が $\\geq 50\\%$ 最大効果を発揮します（有効域）。
%[text] $C \\geq MTC$（最小毒性濃度; minimum toxic concentration）のとき副作用が現れる可能性があります。
%[text] ここでは $MTC = 8 \\cdot EC50$ を目安の安全マージンとして使用します（コード定数 MTC\_FACTOR）。
%[text] 
%[text] EC50 以上の時間 $T(eff)$ は薬物が意味のある効果を発揮する時間ウィンドウを近似し、有効な投与間隔の指標となります。
%[text] アスピリンは急激なスパイク後 2 h 以内にほぼ完全に消失し、カフェインは単回投与から 12 h 以上にわたる持続した低濃度暴露を示します。最適なプロファイルは臨床目標（急性治療 vs 慢性治療）に依存します。
EMAX       = 100.0;   % % effect (maximum = 100%)
N_HILL     = 1;       % Hill coefficient (n=1: no cooperativity)
MTC_FACTOR = 8.0;     % MTC = MTC_FACTOR * EC50 (indicative safety margin)
logInfo("Emax PD 解析 (n=%d, Emax=%.0f%%):", N_HILL, EMAX); %[output:385b9479]
logInfo("  %-16s %6s %6s %8s %7s %7s", ... %[output:group:83b3d3bb] %[output:7765b461]
    "薬物", "EC50", "MTC", "T>EC50", "Cmax", "安全?"); %[output:group:83b3d3bb] %[output:7765b461]
logInfo("  %s", repmat("-", 1, 56)); %[output:8d496dc9]
T_eff  = zeros(1, nDrugs);
isSafe = false(1, nDrugs);
for k = 1:nDrugs %[output:group:41031007]
    C_k   = pkSim(k).C;
    t_k   = pkSim(k).t;
    MTC_k = MTC_FACTOR * pkDB(k).EC50;
    % Time above EC50 (trapezoidal integration of logical indicator)
    above_EC50 = C_k >= pkDB(k).EC50;
    T_eff(k)   = trapz(t_k, double(above_EC50));
    % Safety: peak concentration below indicative MTC
    isSafe(k) = pkSim(k).Cmax < MTC_k;
    logInfo("  %-16s %6.1f %6.1f %8.2f %7.2f %7s", ... %[output:7223f5d3]
        pkDB(k).Name, pkDB(k).EC50, MTC_k, T_eff(k), pkSim(k).Cmax, ... %[output:7223f5d3]
        upper(string(isSafe(k)))); %[output:7223f5d3]
end %[output:group:41031007]
%[text] \--- Figure 5: 効果プロファイルと $T(eff)$ ---
figure("Name", "R02 Sec6: Emax PD Effect Profiles"); %[output:8daa9619]
tiledlayout(1, 2, TileSpacing="compact"); %[output:8daa9619]
nexttile; %[output:8daa9619]
hold on; %[output:8daa9619]
for k = 1:nDrugs
    C_k = pkSim(k).C;
    E_k = EMAX .* C_k.^N_HILL ./ (pkDB(k).EC50^N_HILL + C_k.^N_HILL);
    plot(pkSim(k).t, E_k, "Color", pkDB(k).Color, ... %[output:8daa9619]
        LineWidth=2, DisplayName=pkDB(k).Name); %[output:8daa9619]
end
yline(50, "--k", "50% E_{max}  (EC50 閾値)", ... %[output:8daa9619]
    LabelHorizontalAlignment="left", HandleVisibility="off"); %[output:8daa9619]
xlabel("時間 (h)"); %[output:8daa9619]
ylabel("効果 (% E_{max})"); %[output:8daa9619]
title("Emax PD 効果プロファイル"); %[output:8daa9619]
legend(Location="northeast"); %[output:8daa9619]
ylim([0, 105]); %[output:8daa9619]
xlim([0, T_SIM]); %[output:8daa9619]
grid on; %[output:8daa9619]
nexttile; %[output:8daa9619]
colors_rgb = [0.886 0.290 0.200; 0.204 0.541 0.741; ...
              0.596 0.557 0.835; 0.467 0.467 0.467];
bar_h        = bar(T_eff, FaceColor="flat"); %[output:8daa9619]
bar_h.CData  = colors_rgb; %[output:8daa9619]
set(gca, "XTickLabel", {pkDB.Name}, "XTickLabelRotation", 30); %[output:8daa9619]
ylabel("EC50 以上の時間 (h)"); %[output:8daa9619]
title("1 回投与あたりの有効期間"); %[output:8daa9619]
grid on; %[output:8daa9619]
sgtitle("Emax 薬力学 — 効果 vs 時間"); %[output:8daa9619]
%%
%[text] ## Section 7: Lipinski 記述子と PK 指標の相関
%[text] ### Ro5 が予測するもの・できないもの
%[text] よくある誤解として「Lipinski 適合分子は PK が良い」というものがあります。Ro5 は吸収（バイオアベイラビリティ $F$）を予測するために設計されており、分布（$Vd$）や消失速度（$CL$、$t(1/2)$）を予測するものではありません。
%[text] 
%[text] この n=4 の小データセットで予想される観察を以下に示します。LogP は $Vd$ と弱い相関を持つかもしれません。親油性の薬物は組織に分配されやすく $Vd$ が上昇しますが、例外も多くあります。
%[text] MW は $t(1/2)$ と相関しません。クリアランスは CYP450 酵素活性と腎濾過によって支配され、分子量とは無関係です。4 薬物全てが Ro5 に合格しつつも $t(1/2)$ は 0.33 h（アスピリン）から 10.3 h（カフェイン）と劇的に異なります。
%[text] ただし n=4 は統計的結論を出すには少なすぎる点に注意してください。このセクションは概念的デモンストレーションです。
logInfo("pkDB 薬物の Lipinski 相関のために RDKit 記述子を計算中 ..."); %[output:176503e4]
pkMW   = zeros(1, nDrugs);
pkLogP = zeros(1, nDrugs);
pkVd   = zeros(1, nDrugs);
pkHalf = zeros(1, nDrugs);
for k = 1:nDrugs
    mol_k    = emk.mol.fromSmiles(pkDB(k).SMILES);
    d_k      = emk.descriptor.calculate(mol_k, ["MolWt", "LogP"]);
    pkMW(k)  = d_k.MolWt;
    pkLogP(k)= d_k.LogP;
    pkVd(k)  = pkDB(k).Vd;
    pkHalf(k)= pkSim(k).t_half;
end
r_logp_vd  = corr(pkLogP(:), pkVd(:));
r_mw_thalf = corr(pkMW(:), pkHalf(:));
logInfo("相関 (n=%d — 概念デモンストレーションのみ):", nDrugs); %[output:30e1c7b7]
logInfo("  LogP vs Vd   : Pearson r = %+.3f", r_logp_vd); %[output:76249084]
logInfo("  MW   vs t1/2 : Pearson r = %+.3f", r_mw_thalf); %[output:7ae233e1]
logInfo("  注意: n=4 は統計的結論を出すには少なすぎます。"); %[output:02ccf2d0]
figure("Name", "R02 Sec7: Lipinski Descriptors vs PK Metrics"); %[output:0cfaf89b]
tiledlayout(1, 2, TileSpacing="compact"); %[output:0cfaf89b]
nexttile; %[output:0cfaf89b]
hold on; %[output:0cfaf89b]
for k = 1:nDrugs
    scatter(pkLogP(k), pkVd(k), 100, "filled", ... %[output:0cfaf89b]
        MarkerFaceColor=pkDB(k).Color, MarkerEdgeColor="none"); %[output:0cfaf89b]
    text(pkLogP(k) + 0.05, pkVd(k) + 0.8, pkDB(k).Name, FontSize=9);
end
xlabel("LogP (Wildman-Crippen)"); %[output:0cfaf89b]
ylabel("分布容積 V_d (L)"); %[output:0cfaf89b]
title(sprintf("LogP vs V_d  (r = %+.2f,  n=%d)", r_logp_vd, nDrugs)); %[output:0cfaf89b]
grid on;  box on; %[output:0cfaf89b]
nexttile; %[output:0cfaf89b]
hold on; %[output:0cfaf89b]
for k = 1:nDrugs
    scatter(pkMW(k), pkHalf(k), 100, "filled", ... %[output:0cfaf89b]
        MarkerFaceColor=pkDB(k).Color, MarkerEdgeColor="none"); %[output:0cfaf89b]
    text(pkMW(k) + 0.5, pkHalf(k) + 0.15, pkDB(k).Name, FontSize=9);
end
xlabel("分子量 (g/mol)"); %[output:0cfaf89b]
ylabel("消失半減期 t_{1/2} (h)"); %[output:0cfaf89b]
title(sprintf("MW vs t_{1/2}  (r = %+.2f,  n=%d)", r_mw_thalf, nDrugs)); %[output:0cfaf89b]
grid on;  box on; %[output:0cfaf89b]
sgtitle("Lipinski 記述子 vs PK 指標  (n=4, 概念デモンストレーション)"); %[output:0cfaf89b]
